import React, { useState } from 'react';

export default function ActivityTimeline({ activities }) {
  const [expandedId, setExpandedId] = useState(null);

  const toggleExpand = (id) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const icons = {
    comment: (
      <svg className="w-4 h-4 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
    ),
    action: (
      <svg className="w-4 h-4 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>
    ),
    alert: (
      <svg className="w-4 h-4 text-yellow-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
    )
  };

  const bgColors = {
    comment: "bg-blue-100",
    action: "bg-green-100",
    alert: "bg-yellow-100"
  };

  return (
    <div className="relative border-l border-gray-200 ml-6 pl-6 flex flex-col gap-6 max-w-md mx-auto py-10 font-sans">
      {activities.map((act) => {
        const isExpanded = expandedId === act.id;
        return (
          <div key={act.id} className="relative">
            {/* Absolute Timeline Dot Icon */}
            <span className={`absolute -left-[37px] top-0 flex items-center justify-center w-6 h-6 rounded-full border-2 border-white dark:border-gray-900 ${bgColors[act.category]}`}>
              {icons[act.category]}
            </span>

            {/* Content card */}
            <div
              onClick={() => toggleExpand(act.id)}
              className="cursor-pointer border border-gray-150 rounded-xl p-4 bg-white hover:bg-gray-50 transition shadow-xs"
            >
              <div className="flex justify-between items-start">
                <span className="text-sm font-semibold text-gray-800">{act.title}</span>
                <span className="text-xs text-gray-400">{act.time}</span>
              </div>
              <p className="text-xs text-gray-500 mt-1 leading-relaxed">{act.description}</p>

              {isExpanded && act.details && (
                <div className="mt-3 pt-3 border-t border-gray-100 text-xs text-gray-600 bg-gray-50/50 p-2.5 rounded-lg animate-fade-in leading-relaxed">
                  {act.details}
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}
